import SwiftUI
import SwiftData

struct GameplayView: View { let challenge: ChallengeKind; let packID: String; @Environment(\.modelContext) private var modelContext; @StateObject private var engine = GameEngine(); private let analyzer = BodyPoseAnalyzer(); @State private var task: Task<Void, any Error>?; @State private var goResult = false; var body: some View { ZStack(alignment:.bottom) { ARViewContainer(challenge:challenge); GameplayHUD(engine:engine) }.navigationTitle(challenge.title).navigationBarTitleDisplayMode(.inline).onAppear { begin() }.onDisappear { task?.cancel() }.navigationDestination(isPresented:$goResult) { ResultsView(summary:.init(id:UUID(), challenge:challenge, score:engine.result.score, stars:engine.result.stars, didWin:engine.result.score >= 350)) } }; private func begin() { engine.prepare(challenge); engine.scan(); engine.startNow(); task = Task { @MainActor in let started = Date(); while !Task.isCancelled && engine.state == .running { let elapsed = Date().timeIntervalSince(started); let pose = await analyzer.demoTick(kind:challenge, elapsed:elapsed); engine.tick(input:.init(elapsed:elapsed, pose:pose, portalTapped:challenge == .portal && elapsed > 4, hits:0)); try? await Task.sleep(nanoseconds:300_000_000) }; let record = GameSessionRecord(challenge:challenge, packID:packID, score:engine.result.score, stars:engine.result.stars, duration:challenge.seconds, didWin:engine.result.score >= 350); modelContext.insert(record); goResult = true } } }
